### 개선 4: 페이지네이션 도입 (데이터 볼륨 제한)

전체 목록을 한 번에 내려주는 구조라면, 커서 기반 페이지네이션으로 한 번에 처리하는 데이터 양 자체를 줄여야 합니다.

```kotlin
// 커서 기반 페이지네이션 쿼리
fun findFollowingListWithCursor(
    followerUserId: String,
    cursor: String?,   // 마지막으로 받은 followId
    limit: Int = 20
): List<FollowingDto> {
    return queryFactory
        .select(/* ... */)
        .from(follow)
        .innerJoin(user).on(follow.followeeUserId.eq(user.id))
        .leftJoin(profile).on(user.id.eq(profile.userId))
        .where(
            follow.followerUserId.eq(followerUserId),
            cursor?.let { follow.id.lt(it) }  // 커서 이후 데이터만
        )
        .orderBy(follow.createdAt.desc())
        .limit(limit.toLong())
        .fetch()
}
```

