### 개선 5: GraphQL DataLoader 적용

```kotlin
// FollowDataLoader.kt
@Component
class UserProfileDataLoader(
    private val profileRepository: ProfileRepository
) : BatchLoader<String, ProfileDto> {

    override fun load(userIds: List<String>): CompletionStage<List<ProfileDto>> {
        return CompletableFuture.supplyAsync {
            // IN 절로 한 번에 조회
            val profiles = profileRepository.findByUserIdIn(userIds)
            val profileMap = profiles.associateBy { it.userId }
            userIds.map { profileMap[it] ?: ProfileDto.empty() }
        }
    }
}
```

